"use client"

import { X, Minus, Plus, Trash2, ShoppingBag } from 'lucide-react'
import { useState } from 'react'

interface CartDrawerProps {
  onCheckout: () => void
}

export function CartDrawer({ onCheckout }: CartDrawerProps) {
  const [isOpen, setIsOpen] = useState(false)
  // Simulación de carrito vacío para evitar errores de contexto
  const cartItems: any[] = [] 

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-24 z-40 bg-[#7c3aed] text-white p-4 rounded-full shadow-lg hover:bg-[#6d28d9] transition-transform hover:scale-110"
      >
        <ShoppingBag className="w-6 h-6" />
        {cartItems.length > 0 && (
          <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs w-5 h-5 rounded-full flex items-center justify-center">
            {cartItems.length}
          </span>
        )}
      </button>
    )
  }

  return (
    <>
      <div 
        className="fixed inset-0 bg-black/50 z-50 backdrop-blur-sm"
        onClick={() => setIsOpen(false)}
      />
      <div className="fixed right-0 top-0 h-full w-full max-w-md bg-[#1a1a1f] text-white z-[60] shadow-2xl flex flex-col animate-in slide-in-from-right">
        <div className="p-4 border-b border-[#2d2d35] flex items-center justify-between">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <ShoppingBag className="w-5 h-5" /> Tu Carrito
          </h2>
          <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-[#2d2d35] rounded-full">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 flex flex-col items-center justify-center text-gray-400">
           <ShoppingBag className="w-16 h-16 mb-4 opacity-20" />
           <p>Tu carrito está vacío</p>
           <button 
            onClick={() => setIsOpen(false)}
            className="mt-4 text-[#7c3aed] hover:underline"
           >
             Continuar comprando
           </button>
        </div>

        <div className="p-4 border-t border-[#2d2d35] bg-[#1a1a1f]">
          <div className="flex justify-between mb-4 text-lg font-bold">
            <span>Total</span>
            <span>$0.00 MXN</span>
          </div>
          <button
            disabled
            className="w-full py-4 bg-gray-700 text-gray-400 rounded-xl font-bold cursor-not-allowed"
          >
            Finalizar Compra
          </button>
        </div>
      </div>
    </>
  )
}