"use client"

import { useState } from 'react'
import { ChevronDown, X, SlidersHorizontal } from 'lucide-react'
import { PlatformIcon } from './platform-icons'

// Datos locales para sustituir @/lib/game-data
const productTypes = [
  { id: 'juego-base', name: 'Juego Base' },
  { id: 'dlc', name: 'DLC / Expansión' },
  { id: 'tarjeta-regalo', name: 'Tarjeta de Regalo' }
]

const platforms = [
  { id: 'steam', name: 'Steam' },
  { id: 'xbox', name: 'Xbox' },
  { id: 'playstation', name: 'PlayStation' },
  { id: 'nintendo', name: 'Nintendo' }
]

const genres = ['Acción', 'Aventura', 'RPG', 'Estrategia', 'Deportes', 'Simulación']
const regions = ['Global', 'Latinoamérica', 'Europa', 'Norteamérica']

// Función cn local
const cn = (...classes: (string | boolean | undefined)[]) => classes.filter(Boolean).join(' ')

export interface Filters {
  types: string[]
  platforms: string[]
  genres: string[]
  regions: string[]
  priceRange: [number, number]
}

interface SidebarFiltersProps {
  filters: Filters
  onFiltersChange: (filters: Filters) => void
  isMobileOpen: boolean
  onMobileClose: () => void
}

interface FilterSectionProps {
  title: string
  children: React.ReactNode
  defaultOpen?: boolean
}

function FilterSection({ title, children, defaultOpen = true }: FilterSectionProps) {
  const [isOpen, setIsOpen] = useState(defaultOpen)

  return (
    <div className="border-b border-[#2d2d35] pb-4 mb-4 last:border-0 last:pb-0 last:mb-0">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center justify-between w-full text-left mb-3"
      >
        <span className="font-semibold text-white">{title}</span>
        <ChevronDown className={cn("w-4 h-4 text-[#9ca3af] transition-transform", isOpen && "rotate-180")} />
      </button>
      {isOpen && <div className="space-y-2">{children}</div>}
    </div>
  )
}

export function SidebarFilters({ filters, onFiltersChange, isMobileOpen, onMobileClose }: SidebarFiltersProps) {
  const handleTypeToggle = (typeId: string) => {
    const newTypes = filters.types.includes(typeId)
      ? filters.types.filter(t => t !== typeId)
      : [...filters.types, typeId]
    onFiltersChange({ ...filters, types: newTypes })
  }

  const handlePlatformToggle = (platformId: string) => {
    const newPlatforms = filters.platforms.includes(platformId)
      ? filters.platforms.filter(p => p !== platformId)
      : [...filters.platforms, platformId]
    onFiltersChange({ ...filters, platforms: newPlatforms })
  }

  const handlePriceChange = (value: number, index: 0 | 1) => {
    const newRange: [number, number] = [...filters.priceRange] as [number, number]
    newRange[index] = value
    onFiltersChange({ ...filters, priceRange: newRange })
  }

  const clearFilters = () => {
    onFiltersChange({
      types: [],
      platforms: [],
      genres: [],
      regions: [],
      priceRange: [0, 2000]
    })
  }

  const hasActiveFilters = 
    filters.types.length > 0 ||
    filters.platforms.length > 0 ||
    filters.priceRange[0] > 0 ||
    filters.priceRange[1] < 2000

  const filterContent = (
    <>
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-2">
          <SlidersHorizontal className="w-5 h-5 text-[#7c3aed]" />
          <h2 className="text-lg font-bold text-white">Filtros</h2>
        </div>
        {hasActiveFilters && (
          <button onClick={clearFilters} className="text-sm text-[#7c3aed] hover:text-[#9d6eff]">
            Limpiar
          </button>
        )}
      </div>

      <FilterSection title="Tipo de Producto">
        {productTypes.map((type) => (
          <label key={type.id} className="flex items-center gap-3 cursor-pointer group" onClick={() => handleTypeToggle(type.id)}>
            <div className={cn(
              "w-5 h-5 rounded border-2 flex items-center justify-center transition-colors",
              filters.types.includes(type.id) ? "bg-[#7c3aed] border-[#7c3aed]" : "border-[#3f3f46]"
            )}>
              {filters.types.includes(type.id) && <div className="w-2 h-2 bg-white rounded-sm" />}
            </div>
            <span className="text-sm text-[#9ca3af] group-hover:text-white">{type.name}</span>
          </label>
        ))}
      </FilterSection>

      <FilterSection title="Plataforma">
        <div className="grid grid-cols-2 gap-2">
          {platforms.map((platform) => (
            <button
              key={platform.id}
              onClick={() => handlePlatformToggle(platform.id)}
              className={cn(
                "flex items-center gap-2 px-3 py-2 rounded-lg text-sm transition-all",
                filters.platforms.includes(platform.id) ? "bg-[#7c3aed] text-white" : "bg-[#252529] text-[#9ca3af]"
              )}
            >
              <PlatformIcon platform={platform.id} className="w-4 h-4" />
              <span className="truncate">{platform.name}</span>
            </button>
          ))}
        </div>
      </FilterSection>

      <FilterSection title="Rango de Precio">
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <input
              type="number"
              value={filters.priceRange[1]}
              onChange={(e) => handlePriceChange(Number(e.target.value), 1)}
              className="w-full p-2 bg-[#252529] border border-[#2d2d35] rounded-lg text-white text-sm"
            />
          </div>
          <input
            type="range"
            min="0"
            max="2000"
            value={filters.priceRange[1]}
            onChange={(e) => handlePriceChange(Number(e.target.value), 1)}
            className="w-full h-1 bg-[#252529] rounded-lg appearance-none cursor-pointer accent-[#7c3aed]"
          />
        </div>
      </FilterSection>
    </>
  )

  return (
    <>
      <aside className="hidden lg:block w-64 flex-shrink-0">
        <div className="sticky top-24 bg-[#1a1a1f] rounded-xl p-5 border border-[#2d2d35]">
          {filterContent}
        </div>
      </aside>

      {isMobileOpen && (
        <div className="lg:hidden fixed inset-0 z-[100] flex">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onMobileClose} />
          <div className="relative w-80 bg-[#1a1a1f] h-full p-5 overflow-y-auto">
            <div className="flex justify-between mb-6">
              <h2 className="text-white font-bold text-xl">Filtros</h2>
              <button onClick={onMobileClose}><X className="text-white" /></button>
            </div>
            {filterContent}
          </div>
        </div>
      )}
    </>
  )
}