"use client"

import { useState } from 'react'
import { ShoppingCart, Search, Menu, User, Globe, Moon, Sun, ChevronDown } from 'lucide-react'
import { useCart } from '@/lib/cart-context'
import { useCurrency, regions } from '@/lib/currency-context'
import { cn } from '@/lib/utils'

interface HeaderProps {
  onSearch: (query: string) => void
  searchQuery: string
  onLoginClick: () => void
}

export function Header({ onSearch, searchQuery, onLoginClick }: HeaderProps) {
  const { totalItems, setIsCartOpen } = useCart()
  const { region, setRegion } = useCurrency()
  const [isMenuOpen, setIsMenuOpen] = useState(false)
  const [isCurrencyOpen, setIsCurrencyOpen] = useState(false)

  const currentRegion = regions.find(r => r.id === region) || regions[0]

  return (
    <header className="sticky top-0 z-50 w-full bg-[#101014]/80 backdrop-blur-md border-b border-[#1a1a1f]">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between gap-4">
        
        {/* Logo */}
        <div className="flex items-center gap-2 flex-shrink-0">
          <div className="w-8 h-8 bg-[#7c3aed] rounded-lg flex items-center justify-center font-bold text-white shadow-lg shadow-[#7c3aed]/20">
            R
          </div>
          <span className="text-xl font-bold tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400 hidden sm:block">
            RANDOMPLAY
          </span>
        </div>

        {/* Barra de Búsqueda */}
        <div className="flex-1 max-w-xl relative group">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500 group-focus-within:text-[#7c3aed] transition-colors" />
          <input
            type="text"
            placeholder="Buscar juegos, tarjetas, DLC..."
            value={searchQuery}
            onChange={(e) => onSearch(e.target.value)}
            className="w-full bg-[#1a1a1f] border border-[#2d2d35] rounded-full py-2 pl-10 pr-4 text-sm focus:outline-none focus:border-[#7c3aed] transition-all"
          />
        </div>

        {/* Acciones */}
        <div className="flex items-center gap-2 sm:gap-4">
          
          {/* Selector de Moneda */}
          <div className="relative">
            <button
              onClick={() => setIsCurrencyOpen(!isCurrencyOpen)}
              className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-[#1a1a1f] transition-colors text-xs font-medium text-gray-300"
            >
              <span>{currentRegion.flag}</span>
              <span className="hidden md:block uppercase">{currentRegion.currency}</span>
              <ChevronDown className={cn("w-3 h-3 transition-transform", isCurrencyOpen && "rotate-180")} />
            </button>

            {isCurrencyOpen && (
              <div className="absolute top-full right-0 mt-2 w-40 bg-[#1a1a1f] border border-[#2d2d35] rounded-xl shadow-2xl p-1 overflow-hidden animate-in fade-in slide-in-from-top-2">
                {regions.map((r) => (
                  <button
                    key={r.id}
                    onClick={() => {
                      setRegion(r.id)
                      setIsCurrencyOpen(false)
                    }}
                    className={cn(
                      "w-full flex items-center gap-3 px-3 py-2 text-xs rounded-lg transition-colors",
                      region === r.id ? "bg-[#7c3aed] text-white" : "text-gray-400 hover:bg-[#2d2d35] hover:text-white"
                    )}
                  >
                    <span>{r.flag}</span>
                    <span className="font-semibold">{r.currency}</span>
                    <span className="text-[10px] opacity-60 ml-auto">{r.name}</span>
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Carrito */}
          <button
            onClick={() => setIsCartOpen(true)}
            className="relative p-2.5 rounded-lg text-gray-400 hover:text-white hover:bg-[#1a1a1f] transition-all"
          >
            <ShoppingCart className="w-5 h-5" />
            {totalItems > 0 && (
              <span className="absolute -top-1 -right-1 bg-[#ef4444] text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold animate-bounce">
                {totalItems}
              </span>
            )}
          </button>

          {/* Botón Entrar */}
          <button
            onClick={onLoginClick}
            className="hidden sm:flex items-center gap-2 bg-[#7c3aed] hover:bg-[#6d28d9] px-4 py-2 rounded-lg text-sm font-bold transition-all"
          >
            <User className="w-4 h-4" />
            Entrar
          </button>

          <button className="sm:hidden p-2 text-gray-400 hover:text-white">
            <Menu className="w-6 h-6" />
          </button>
        </div>
      </div>
    </header>
  )
}